public class FileUploadController : ControllerBase
{
    private readonly string _uploadsPath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot/uploads");

    [HttpPost]
    public IActionResult UploadFile()
    {
        var files = Request.Form.Files;
        if (files.Count == 0)
            return BadRequest("No file provided.");

        foreach (var file in files)
        {
            if (!ValidateFileType(file.FileName))
                return BadRequest($"Invalid file type: {file.FileName}");

            var filePath = GenerateServerSideFilename(file);
            using (var stream = new FileStream(filePath, FileMode.CreateNew))
            {
                file.CopyTo(stream);
