            // Apply size limits
            if (file.Length > 10 * 1024 * 1024)
                return BadRequest("File too large.");

            // Content checks and archive safety checks
            var contentType = GetContentType(file.ContentType);
            if (!contentType.IsImage() && !contentType.IsPdf() && !contentType.IsOfficeDocument())
                return BadRequest($"Unsupported file type: {file.FileName}");

            // Image/document processing safeguards
            if (contentType.IsImage())
